    // STRY0093948 - the tasker form with tab is rasing this as a rootscope broadcast, updated to catch
    $rootScope.$on('$taskerTabbedForm.drillDownList.click', function(e, parms) {
        // NOTE: this does not post back to the server, so no reason to reset the header and footer diagram objects in Task Tree
        if (diagram == undefined) {
            return;
        }
        // if the event was not raised on the table associated with this widget, ignore the click
        if (c.data.table == parms.table && c.data.sys_id != parms.sys_id) {
            c.data.sys_id = parms.sys_id;
            // STRY0074663 Only rebroadcast if the node changed
            if (c.data.selectedId != parms.sys_id) {
                c.data.selectedId = parms.sys_id;
                // Select the node using the sys_id parameter supplied.
                var node_select = diagram.findNodeForKey(c.data.selectedId);
                diagram.select(node_select);
            }
        }
    });

    $rootScope.$on('$TaskerTaskList.click', function(e, parms) {
        if (diagram == undefined) {
            return;
        }
        // if the item is already selected ignore the click
        if (c.data.sys_id != parms.sys_id) {
            c.data.sys_id = parms.sys_id;
            // STRY0074663 Only rebroadcast if the node changed
            if (c.data.selectedId != parms.sys_id) {
                c.data.selectedId = parms.sys_id;
                // Select the node using the sys_id parameter supplied.
                var node_select = diagram.findNodeForKey(c.data.selectedId);
                diagram.select(node_select);
            }
        }
    });

    $scope.$on("field.change", function(evt, parms) {
        if (parms.field.name == 'page')
            changePage(parms.newValue);
    });

    function changePage(p) {
        var path = $location.path();
        var searchParms = $location.search();
        $location.search({
            id: searchParms.id,
            p: p
        });
    }

