    $scope.getMap = function() {
        $scope.toggleCollpased();
        loadMap();
    };

    $scope.toggleCollpased = function() {
        // you are here, why does toggle get messed up after second click		
        if (c.data.hide_accordion) {
            c.data.isNotCollapsed = true;
        } else {
            c.data.isNotCollapsed = !c.data.isNotCollapsed;
        }
    };

    // DFCT0010652
    function loadMap() {
        if (c.data.map == undefined || c.data.map.length == 0) {
            $scope.data.loadData = true;
            // DFCT0010652
            $scope.hide_accordion = c.data.hide_accordion;
            // TREE FOOTER TOOLBAR
            // STRY0117600 - does not like diagram posted back to server
            if (c.data.widgetTreeFooterToolbars) {
                c.data.widgetTreeFooterToolbars[0].diagram = null;
            }
            if (c.data.widgetTreeHeaderToolbars) {
                c.data.widgetTreeHeaderToolbars[0].diagram = null;
            }
            spUtil.update($scope).then(function(data) {
                if (c.data.widgetTreeHeaderToolbars) {
                    // load orientation from the header widget
                    treeOrientation = c.data.widgetTreeHeaderToolbars[0].data.settings.treeOrientation;
                }
                resetDiagram();
                // DFCT0011129
                initRecordWatcher($scope.data.table, "u_task_tree=" + $scope.data.task_tree);
            });
            // DFCT0010674
        } else {
            resetDiagram();
        }
    }
