    $(window).on("resize", function() {
        // not sure why, but increasing the minHeight seems to work, but not sure why
        TREE_CONST.minHeight = 12;
        resizeDiagram();
    });
    // TREE HEADER TOOLBAR
    // STRY0117600 - this event is raised when the switch to horizontal icon is clicked 
    $scope.$on("$tasker-tree-toolbar-icons.switchToHorizontal", function() {
        treeOrientation = "Horizontal";
        treeNodeAngle = 0;
        resetDiagram();
    });

    // TREE HEADER TOOLBAR
    // STRY0117600 - this event is raised when the switch to vertical icon is clicked 
    $scope.$on("$tasker-tree-toolbar-icons.switchToVertical", function() {
        treeOrientation = "Vertical";
        treeNodeAngle = 90;
        resetDiagram();
    });

    function resetDiagram() {
        if (c.data.widgetTreeHeaderToolbars) {
            // set default tree orientation based on system setting (this will change when user perference is enabled)
            if (treeOrientation == 'Horizontal') {
                treeNodeAngle = TREE_CONST.horizontalTreeAngle;
                // this is handles positioning the status indicator
                treeOrientationWithinBorder = "Vertical";
            } else {
                treeNodeAngle = TREE_CONST.verticalTreeAngle;
                // this is handles positioning the status indicator
                treeOrientationWithinBorder = "Horizontal";
            }
        }

        diagramInitCompleted = false;
        // NOTE: updated to use data.topParentTask_id
        if ($scope.data.topParentTask_id) {
            drawTree();
        }
        _setToolbarProperties();
        // STRY0072032 - STRY0123997 no longer killing and rebuilding diagram, no need to destroy overviewdiv
        if (myOverview == undefined) {
            // STRY0116823
            myOverview = $go(go.Overview, "myOverview", {
                observed: diagram
            }); // , contentAlignment: go.Spot.Center
        }
        // DFCT0010275
        if ($scope.data.map.length > 0) {
            // // STRY0072032 - this event handler is called when the diagram is first ready
            // LayoutCompleted fires whenever the layout changes
            diagram.addDiagramListener("InitialLayoutCompleted", function(e) {
                resizeDiagram();
                var node = diagram.findNodeForKey(c.data.selectedId);
                diagram.centerRect(node.actualBounds);
                // the diagram is initialized so the initial scale can be set
                // NOTE: zoomToFit and zoomToRect do not work in this init function
                // so calling a timeout function to initialize the scale
                $timeout(function() {
                    _initializeScale();
                }, 200);
            });

            // TREE FOOTER TOOLBAR
            // STRY0117600 - this event handler is called when the diagram bounds change
            diagram.addDiagramListener("ViewportBoundsChanged", function(e) {
                // set the footer scale when bounds change
                // but wait until init is completed
                if (viewPortHeight != diagram.viewportBounds.height) {
                    // this block only runs once per diagram load
                    if (diagramInitCompleted) {
                        // only need to set scale after initial load
                        // STRY0117945 STRY0121780 (cleared error when toolbar wasn't loaded)
                        if (c.data.widgetTreeFooterToolbars) {
                            c.data.widgetTreeFooterToolbars[0].scale(diagram.scale);
                        }

                    }

                    var node = diagram.findNodeForKey(c.data.selectedId);
                    // and center it and select it
                    // STRY0072032
                    diagram.centerRect(node.actualBounds);
                    viewPortHeight = diagram.viewportBounds.height;
                }

            });
        }
    }
    // ***************************************
    // this block only runs once
    // BEGIN BLOCK
    // ***************************************
    function _initializeScale() {
        if (c.data.widgetTreeFooterToolbars[0].data.isTree) {
            // submit percent change back to server
            diagram.zoomToRect(diagram.documentBounds);
        } else {
            // get the initial scale from the footer widget
            diagram.scale = Number.parseFloat(c.data.widgetTreeFooterToolbars[0].data.settings.diagramScale);
        }
        diagramInitCompleted = true;
    }
    // ***************************************
    // END BLOCK
    // ***************************************

    // TREE FOOTER TOOLBAR
    // STRY0117600 - move toolbar into separate widget to use same functionality across all
    function _setToolbarProperties() {
        // STRY0117600 - pass a reference to diagram to toolbar
        // this sets the diagram on the toolbar so it can handle gojs events in the toolbar
        if (diagramInitCompleted) {
            // this is needed to reset zoom to custom when the diagram changes
            c.data.widgetTreeFooterToolbars[0].resetDiagram(diagram);
        } else {
            c.data.widgetTreeFooterToolbars[0].diagram = diagram;
        }
        // STRY0117600 - pass selectedId to toolbar
        // this sets the selected id on the footer tooltip when the selected id changes
        c.data.widgetTreeFooterToolbars[0].parentSelectedId = c.data.selectedId;
        c.data.widgetTreeFooterToolbars[0].currentTop = c.data.topParentTask_id;

        // STRY0117600 - pass a reference to diagram to toolbar
        // this sets the diagram on the toolbar so it can handle gojs events in the toolbar
        c.data.widgetTreeHeaderToolbars[0].diagram = diagram;
        // STRY0117600 - pass selectedId to toolbar
        // this sets the selected id on the footer tooltip when the selected id changes
        c.data.widgetTreeHeaderToolbars[0].parentSelectedId = c.data.selectedId;
        c.data.widgetTreeHeaderToolbars[0].currentTop = c.data.topParentTask_id;

    }

    function resizeDiagram() {
        // 2.8 | 2022-06-22 | mmcc | STRY0120303 - Task Tree Widget- Add Header and Footer area; deleted all commented out code
        if ($scope.data.map && $scope.data.map.length > 0) {
            // 2.8 | 2022-06-22 | mmcc | STRY0120303 - Task Tree Widget- Add Header and Footer area; no calculating height since using Flexbox
            var node_select = diagram.findNodeForKey(c.data.selectedId);
            diagram.select(node_select);
        }
    }

    // NOTE: YOU ARE HERE
    // TODO: 
    // - Remove all hard coded constants
    // - Review entire widget against Template
    // - Review HTML against template

    function drawTree() {
        if (diagram == undefined) {
            // STRY0072032
            diagram =
                $go(go.Diagram, TREE_CONST.node_id, {
                    initialContentAlignment: go.Spot.Default,
                    allowZoom: true,
                    // define the layout for the diagram
                    layout: $go(go.TreeLayout, {
                        angle: treeNodeAngle,
                        nodeSpacing: TREE_CONST.spacingNode,
                        layerSpacing: TREE_CONST.spacingLayer
                    })
                });
        } else {
            // STRY0072032 - STRY0123997 no longer killing and rebuilding diagram, clear
            diagram.clear();
            diagram.layout.angle = treeNodeAngle;
        }
        diagram.model = new go.TreeModel($scope.data.map);
        diagram.toolManager.hoverDelay = TREE_CONST.toolTipHoverDelay; // default is 850, but for Task Tree set to 200
        // Task Tree only control changing this default
        diagram.toolManager.toolTipDuration = TREE_CONST.toolTipDuration; // default is 5000, but for Task Tree set to 10000

        // Define a simple node template consisting of text followed by an expand/collapse button
        diagram.nodeTemplate = _createNodeTemplate();


        diagram.select(diagram.findNodeForKey(c.data.selectedId));
        diagram.allowVerticalScroll = true;

        // Define a trivial link template with no arrowhead
        diagram.linkTemplate = $go(go.Link, {
            selectable: false
        }, $go(go.Shape)); // the link shape
    }
    // **************************************************************************************************************
    // STRY0119818 - NOTE: reorganized Template and OU to put all of the repeated functions in the same block of code
    // TREE Code functions in all trees 
    // END BLOCK
    // **************************************************************************************************************	

    // **************************************************************************************************************	
    // DRAW TREE AND TREE LAYOUT FUCNTIONS
    // This block contains the functions that define the tree structure and capabilities
    // START BLOCK
    // **************************************************************************************************************	
    // Define a simple node template consisting of text followed by an expand/collapse button
    function _createNodeTemplate() {
        var nodeTemplate =
            $go(go.Node, treeOrientation, {
                    selectionAdorned: false,
                    selectionChanged: nodeSelectionChanged,
                    isTreeExpanded: true,
                    isTreeLeaf: true
                }, // this event handler is defined below
                _createTreeNode()
                // NOTE: The Tree Expander button is a differnt for task tree b/c we have the status indicator still outside the triangle.
                //       When we change the color to a flat color and move the status indicator inside the rectangle this will change to look like all the others.
            );

        return nodeTemplate;
    }

    function _createTreeNode() {
        var treeNode =
            $go(go.Panel, treeOrientationWithinBorder, // everything within the border
                $go(go.Panel, treeOrientation, // the row of status indicators
                    makeIndicator("status", "10"),
                    $go(go.Panel, "Auto",
                        _createOurterRoundedRectangle(),
                        _createVerticalMainPanel()
                    ),
                    // this was overkill for small diagrams
                    $go("TreeExpanderButton", {
                        alignment: go.Spot.Default
                    }, {
                        visible: true
                    })
                )
            );
        return treeNode;
    }

    function _createOurterRoundedRectangle() {
        // STRY0113936, STRY0111888 - set width and height
        var roundedRectangle =
            $go(go.Shape, "RoundedRectangle", {
                    strokeWidth: TREE_CONST.outlineWidth,
                    width: TREE_CONST.nodeOuterRectangelWidth,
                    height: TREE_CONST.nodeOuterRectangelHeight,
                    fill: TREE_CONST.roundedRectangleFill
                },
                new go.Binding("stroke", "isSelected", function(s) {
                    if (s)
                        return TREE_CONST.node_selected_border;
                    else
                        return null;
                }).ofObject(""),
                // if we want to have same border width even on selected, remove this section
                new go.Binding("strokeWidth", "isSelected", function(s) {
                    if (s)
                        return TREE_CONST.node_selected_border_stroke_width;
                    else
                        return null;
                }).ofObject(""),
                // this does not appear to create a dashed border.  not sure if it is broken or if dash is not recognized
                new go.Binding("strokeDashArray", "isSelected", function(s) {
                    if (s)
                        return "dash";
                    else
                        return null;
                }).ofObject(""),
                // NOTE: fill is different b/c it is based on state until we remove the color from the bacground
                new go.Binding("fill", "state", function(t) {
                    return getStateColors(t, "bg");
                })
            );
        return roundedRectangle;
    }

    function _createVerticalMainPanel() {
        var mainPanel =
            $go(go.Panel, "Auto",
                $go(go.Panel, "Vertical",
                    // DFCT0011134 - STRY0127737 - change name and number display
                    $go(go.Panel, "Horizontal",

                        _createNumberHeader(),
                        _createIconPanel()
                    ),
                    // DFCT0010761 =- changed the height to 35, marin to margin: new go.Margin(0, 5, 0, 5),
                    $go(go.Panel, "Vertical", {
                            alignment: go.Spot.Left,
                            margin: TREE_CONST.nodeTextPanelMargin,
                            minSize: new go.Size(TREE_CONST.textPanelMinWidth, TREE_CONST.textPanelMinHeight),
                            maxSize: new go.Size(TREE_CONST.textPanelMaxWidth, TREE_CONST.textPanelMaxHeight)
                        },
                        $go(go.TextBlock, {
                                alignment: go.Spot.Left,
                                text: "verticalAlignment: Center",
                                textAlign: "left",
                                wrap: go.TextBlock.WrapFit,
                                font: TREE_CONST.fontStyle,
                                stroke: TREE_CONST.textStrokeColor
                            },
                            new go.Binding("stroke", "state", function(t) {
                                return getStateColors(t, "text");
                            }),
                            new go.Binding("text", "name")
                        ),
                        $go(go.TextBlock, {
                                alignment: go.Spot.Left,
                                text: "verticalAlignment: Center",
                                textAlign: "left",
                                wrap: go.TextBlock.WrapFit,
                                font: TREE_CONST.fontStyleNodeDetails,
                                stroke: TREE_CONST.textStrokeColor
                            },
                            new go.Binding("stroke", "state", function(t) {
                                return getStateColors(t, "text");
                            }),
                            new go.Binding("text", "nodeDetails")
                        )
                    )
                )
            );
        return mainPanel;
    }

    openIconForm = function(obj, iconName) {
        switch (iconName) {
            case 'AddIcon':
                openCreateModal(obj);
                break;
            case 'DurationIcon':
                openDurationModal(obj);
                break;
            case 'UserIcon':
                openAssignmentModal(obj);
                break;
            case 'OperationalIcon':
                openOperationalModal(obj);
                break;
        }
    };

    function _createNumberHeader() {
        var numberHeader =
            $go(go.TextBlock, {
                    alignment: go.Spot.Left,
                    width: TREE_CONST.numberPanelWidth
                },


                {
                    font: TREE_CONST.fontStyleTaskerNumber
                },
                new go.Binding("text", "", function(data) {
                    return data.taskernumber;
                }),
                new go.Binding("stroke", "", function(data) {
                    var iconStroke = getStateColors(data.state, "text");
                    return iconStroke;
                })
            );
        return numberHeader;
    }

    function _createIcon(iconName, iconText) {
        var icon =
            $go(go.TextBlock, {
                    name: iconName,
                    text: iconText,
                    margin: new go.Margin(TREE_CONST.icon_top_margin, TREE_CONST.icon_right_margin, TREE_CONST.icon_bottom_margin, TREE_CONST.icon_left_margin),
                    alignment: go.Spot.Right,
                    font: TREE_CONST.icon_font,
                    editable: false,
                    isMultiline: false,
                    isActionable: true,
                    click: function(e, obj) {
                        openIconForm(obj, iconName);
                        e.handled = true;
                    },
                    mouseEnter: function(e, obj) {
                        obj.saveStroke = obj.stroke;
                        obj.stroke = getStateColors(obj.part.data.state, "hover");
                    },
                    mouseLeave: function(e, obj) {
                        obj.stroke = obj.saveStroke;
                        obj.saveStroke = null;
                    }
                },
                new go.Binding("toolTip", "", function(nodeData) {
                    return toolTipJSON(iconName, nodeData);
                }),
                new go.Binding("text", "", function(data) {
                    if (iconName == 'ExclamationIcon') {
                        if (data.warning.noSuspenseDate || !data.warning.isSuspenseDateAfterChildren ||
                            data.warning.isSuspenseDateAfterParent || data.warning.waitStatewithNoSubtasks ||
                            data.warning.isTopSuspenseDateAfterExternalInboundDate || data.warning.isTopSuspenseDateBeforeExternalOutboundDate ||
                            data.warning.primaryAssigneeEmpty || data.warning.assignedMemberEmpty)
                            return TREE_CONST.font_awesome_exclamation_triangle_o;
                        else
                            return '';
                    } else {
                        return iconText;
                    }
                }),
                //this binds the stroke color to the level property of the data mapping, the function uses the level to determine the color
                //the fake logic sets the warning color, otherwise use the default color.
                new go.Binding("stroke", "", function(data) {
                    var iconStroke = getStateColors(data.state, "text");
                    switch (iconName) {
                        case 'UserIcon':
                            // STRY0095897
                            if (data.warning.primaryAssigneeEmpty || data.warning.assignedMemberEmpty)
                                iconStroke = getStateColors(data.state, "warning");
                            else
                                iconStroke = getStateColors(data.state, "text");
                            break;
                        case 'DurationIcon':
                            if (data.warning.noSuspenseDate || !data.warning.isSuspenseDateAfterChildren ||
                                data.warning.isTopSuspenseDateAfterExternalInboundDate || data.warning.isTopSuspenseDateBeforeExternalOutboundDate ||
                                data.warning.isSuspenseDateAfterParent || data.warning.waitStatewithNoSubtasks)
                                iconStroke = getStateColors(data.state, "warning");
                            else
                                iconStroke = getStateColors(data.state, "text");
                            break;
                        case 'ExclamationIcon':
                            iconStroke = getStateColors(data.state, "warning");
                            break;
                    }
                    return iconStroke;
                }),
                new go.Binding("visible", "", function(data) {
                    if (iconName == 'AddIcon') {
                        return (data.canCreateSubTask == true);
                    } else {
                        return true;
                    }
                })
            );
        return icon;
    }

    function _createIconPanel() {
        // STRY0109208 - Add Create Icon
        var iconPanel =
            $go(go.Panel, "Horizontal",
                // removing width allows the width to be size of text.
                {
                    alignment: go.Spot.Right,
                    width: TREE_CONST.icon_panel_width,
                    isOpposite: true
                },

                _createIcon('AddIcon', TREE_CONST.font_awesome_plus_o),
                _createIcon('DurationIcon', TREE_CONST.font_awesome_calendar_o),
                _createIcon('UserIcon', TREE_CONST.font_awesome_user_o),
                // STRY0124682
                _createIcon('OperationalIcon', TREE_CONST.font_awesome_info_o),
                //this binds the exclamation icon to the duration warning  property of the data mapping, 
                //the function uses the level determine if the icon is added or not
                _createIcon('ExclamationIcon', TREE_CONST.icon_warning_stroke)
            );
        return iconPanel;
    }

    // common styling for each indicator
    function makeIndicator(propName, label) { // the data property name
        return $go(go.Shape,
            "Circle", {
                width: 12,
                height: 12,
                fill: "white",
                strokeWidth: 0,
                margin: 5
            },
            new go.Binding("fill", propName, function(t) {
                switch (t) {
                    case ("Projected on time"):
                        return TREE_CONST.node_status_ontime;
                    case ("Warning"):
                        return TREE_CONST.node_status_warning;
                    case ("Critical"):
                        return TREE_CONST.node_status_critical;
                    default:
                        return "Gray";
                }
            })
        );
    }
