    function _createTableColumn(visibleFlag, rowNum, columnNum, spanMultipleInt, columnWidth, margin, textAlignment, text) {
        var tableColumn;
        tableColumn =
            $go(go.TextBlock, {
                    visible: visibleFlag,
                    row: rowNum,
                    column: columnNum,
                    columnSpan: spanMultipleInt,
                    width: columnWidth,
                    margin: margin,
                    alignment: textAlignment,
                    wrap: go.TextBlock.WrapFit,
                    background: TREE_CONST.toolTipBackgroundColor
                },
                text
            );
        return tableColumn;

    }

    // STRY0091260
    function getToolTipText(objectName, nodeData) {
        var toolTip;
        switch (objectName) {
            // // STRY0109208 - Add Create Icon
            case 'AddIcon':
                toolTip =
                    $go(go.Panel, "Table",
                        // Row 1
                        _createTableColumn(true, 0, 0, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Right, c.data.messages["Tasker - Add a Subtask"])
                    );
                break;
            case 'DurationIcon':
                var waitStatewithNoSubtasks = (nodeData.warning.waitStatewithNoSubtasks == true);
                var noSuspenseDate = (nodeData.warning.noSuspenseDate == true);
                var isTopSuspenseDateAfterExternalInboundDate = (nodeData.warning.isTopSuspenseDateAfterExternalInboundDate == true);
                var isTopSuspenseDateBeforeExternalOutboundDate = (nodeData.warning.isTopSuspenseDateBeforeExternalOutboundDate == true);
                var isChildSuspenseDateAfterParent = (nodeData.warning.isSuspenseDateAfterChildren != true);
                var isSuspenseDateAfterParent = (nodeData.warning.isSuspenseDateAfterParent == true);
                var durrationWarningCount = 1;
                toolTip =
                    $go(go.Panel, "Table",
                        // Row 1
                        _createTableColumn(true, 0, 0, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Right, c.data.fieldsInModel.suspense_date.fieldLabel + ": "),
                        _createTableColumn(true, 0, 1, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Left, nodeData.suspense_date_DisplayValue),
                        // Row 2
                        _createTableColumn(waitStatewithNoSubtasks, 1, 0, 2, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipWarningNoteMargin, go.Spot.Left, c.data.messages["Tasker - Warning: Wait state set with no subtasks"]),
                        // Row 3
                        _createTableColumn(noSuspenseDate, 2, 0, 2, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipWarningNoteMargin, go.Spot.Left, c.data.messages["Tasker - Warning: Task has no Suspense Date"]),
                        // Row 4
                        _createTableColumn(isTopSuspenseDateAfterExternalInboundDate, 3, 0, 2, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipWarningNoteMargin, go.Spot.Left, c.data.messages["Tasker - Warning: Internal Suspense date is after the External Suspense Date"]),
                        // Row 5
                        _createTableColumn(isTopSuspenseDateBeforeExternalOutboundDate, 4, 0, 2, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipWarningNoteMargin, go.Spot.Left, c.data.messages["Tasker - Warning: External Suspense Date is after Internal Suspense date for an outbound"]),
                        // Row 6 (width is wider on this message)
                        _createTableColumn(isChildSuspenseDateAfterParent, 5, 0, 2, TREE_CONST.toolTipWarningMessageColumnWidth, TREE_CONST.toolTipWarningNoteMargin, go.Spot.Left, c.data.messages["A Subtask has a Suspense Date AFter this Task"]),
                        // Row 7 (width is wider on this message)
                        _createTableColumn(isSuspenseDateAfterParent, 6, 0, 2, TREE_CONST.toolTipWarningMessageColumnWidth, TREE_CONST.toolTipWarningNoteMargin, go.Spot.Left, c.data.messages["Subtask Suspense Date AFTER Parent Task Suspense Date"])
                    );
                break;
            case 'OperationalIcon':
                var hasSignatureInstructions = (nodeData.u_signature_instructions != 'null');
                var hasDecision = (nodeData.decision != null && nodeData.decision != 'null');
                var decisionText = "";
                if (hasDecision)
                    decisionText = nodeData.decision;
                var hasClassification = (nodeData.classification_DisplayValue != 'null');
                toolTip =
                    $go(go.Panel, "Table",
                        // Row 1 - DFCT0011078 - STRY0127737 - added name to the table to enable seeing the full longer name
                        _createTableColumn(true, 0, 0, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Right, c.data.fieldsInModel.task_name.fieldLabel + ": "),
                        _createTableColumn(true, 0, 1, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Left, nodeData.task_name),
                        // Row 2
                        _createTableColumn(true, 1, 0, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Right, c.data.fieldsInModel.tasker_type.fieldLabel + ": "),
                        _createTableColumn(true, 1, 1, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Left, nodeData.tasker_type_DisplayValue),
                        // Row 3
                        _createTableColumn(hasClassification, 2, 0, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Right, c.data.fieldsInModel.classification.fieldLabel + ": "),
                        _createTableColumn(hasClassification, 2, 1, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Left, nodeData.classification_DisplayValue),
                        // Row 4
                        _createTableColumn(true, 3, 0, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Right, c.data.fieldsInModel.priority.fieldLabel + ": "),
                        _createTableColumn(true, 3, 1, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Left, nodeData.priority_DisplayValue),
                        // Row 5
                        _createTableColumn(true, 4, 0, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Right, c.data.fieldsInModel.risk_flag.fieldLabel + ": "),
                        _createTableColumn(true, 4, 1, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Left, nodeData.risk_flag_DisplayValue),
                        // Row 6
                        _createTableColumn(true, 5, 0, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Right, c.data.fieldsInModel.instructions.fieldLabel + ": "),
                        // 2.7.0 | 2021-06-25 | mmcc | STRY0102408 "Task Tree Manager" tool tip displays "Unicode Decimal Codes"
                        // strip HTML Tags
                        // new go.Binding("text", "", function(data) {
                        //    return data.instructions.replace(/<\/?[^>]+(>|$)/g, "");
                        // convert HTML to a simple string

                        // 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode Decimal Codes when entering 
                        // return _convertHtmlToSimpleString(data.instructions); // function was removed
                        // Need to call below to have <, >, and & show as that character and not an ALT code
                        // return htmlToStringService.convertHtmlToString(data.instructions);															
                        _createTableColumn(true, 5, 1, 1, TREE_CONST.toolTipWarningMessageColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Left, htmlToStringService.convertHtmlToString(nodeData.instructions)),
                        // Row 7
                        _createTableColumn(hasSignatureInstructions, 6, 0, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Right, c.data.fieldsInModel.u_signature_instructions.fieldLabel + ": "),
                        // 2.7.0 | 2021-06-25 | mmcc | STRY0102408 "Task Tree Manager" tool tip displays "Unicode Decimal Codes"
                        // strip HTML Tags
                        // new go.Binding("text", "", function(data) {
                        //    return data.u_signature_instructions.replace(/<\/?[^>]+(>|$)/g, "");
                        // convert HTML to a simple string

                        // 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode Decimal Codes when entering 
                        // return _convertHtmlToSimpleString(data.u_signature_instructions); // function was removed
                        // Need to call below to have <, >, and & show as that character and not an ALT code
                        // return htmlToStringService.convertHtmlToString(data.u_signature_instructions);
                        _createTableColumn(hasSignatureInstructions, 6, 1, 1, TREE_CONST.toolTipWarningMessageColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Left, htmlToStringService.convertHtmlToString(nodeData.u_signature_instructions)),
                        // Row 8
                        _createTableColumn(hasDecision, 7, 0, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Right, c.data.fieldsInModel.decision.fieldLabel + ": "),
                        _createTableColumn(hasDecision, 7, 1, 1, TREE_CONST.toolTipWarningMessageColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Left, decisionText)
                    );
                break;
            case 'UserIcon':
                toolTip =
                    $go(go.Panel, "Table",
                        // Row 1
                        _createTableColumn(true, 0, 0, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Right, c.data.fieldsInModel.tasking_authority.fieldLabel + ": "),
                        _createTableColumn(true, 0, 1, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Left, nodeData.tasking_authority_DisplayValue),
                        // Row 2
                        _createTableColumn(true, 1, 0, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Right, c.data.fieldsInModel.primary_office.fieldLabel + ": "),
                        _createTableColumn(true, 1, 1, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Left, nodeData.primary_office_DisplayValue),
                        // Row 3
                        _createTableColumn(true, 2, 0, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Right, c.data.fieldsInModel.primary_assignee.fieldLabel + ": "),
                        _createTableColumn(true, 2, 1, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Left, nodeData.primary_assignee_DisplayValue),
                        // Row 4
                        _createTableColumn(true, 3, 0, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Right, c.data.fieldsInModel.assigned_to.fieldLabel + ": "),
                        _createTableColumn(true, 3, 1, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Left, nodeData.assigned_to_DisplayValue)
                    );
                break;
            case 'ExclamationIcon':
                // STRY0095748 - no suspensedate warning
                var durationExclamation = (nodeData.warning.noSuspenseDate || nodeData.warning.isTopSuspenseDateAfterExternalInboundDate ||
                    nodeData.warning.isTopSuspenseDateBeforeExternalOutboundDate || !nodeData.warning.isSuspenseDateAfterChildren ||
                    nodeData.warning.isSuspenseDateAfterParent || nodeData.warning.waitStatewithNoSubtasks);
                var assignmentExclamation = (nodeData.warning.primaryAssigneeEmpty || nodeData.warning.assignedMemberEmpty);
                toolTip =
                    $go(go.Panel, "Table",
                        // Row 1
                        _createTableColumn(durationExclamation, 1, 0, 2, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipWarningNoteMargin, go.Spot.Left, c.data.messages["Duration Warning"]),
                        // row 3
                        _createTableColumn(assignmentExclamation, 3, 0, 2, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipWarningNoteMargin, go.Spot.Left, c.data.messages["Tasker -  Warning Assignment"])
                    );
                break;
        }
        return toolTip;
    }

    function toolTipJSON(objectName, nodeData) {
        var toolJSON = $go(go.Adornment, "Spot", "Auto",
            $go(go.Shape, "Rectangle", {
                fill: TREE_CONST.toolTipBackgroundColor
            }),
            getToolTipText(objectName, nodeData)
        );
        return toolJSON;
    }
    // -----------------------------------------------------------------------------------------------------------------
    // END TOOLTIPS
    // -----------------------------------------------------------------------------------------------------------------

};

