//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: KARINA TORRES 
//------------------------------------------------------------------------------------------------------------------------
//------------------------------------------------------------------------------------------------------------------------
// 2.5.21 | 09.08.2020 | KT | UI  | STRY0074067: TECH - Tasker - Unified CSS on widgets (Internal Story, PO story needed)
//------------------------------------------------------------------------------------------------------------------------
// Updates needed on Tasker theme, and also needed on the client script.

#draftTaskPublishMessage {
  height: 30px;
}

.div.panel.panel-default {
  background-color: #F5F5F5!important;
}

.panel-heading .accordion-toggle:after {
    /* symbol for "opening" panels */
    font-family: 'Glyphicons Halflings';  /* essential for enabling glyphicon */
    content: "\e114";    /* adjust as needed, taken from bootstrap.css */
    float: right;        /* adjust as needed */
    color: grey;         /* adjust as needed */
}
.panel-heading .accordion-toggle.collapsed:after {
    /* symbol for "collapsed" panels */
    content: "\e080";    /* adjust as needed, taken from bootstrap.css */
}

.panel-footer .accordion-toggle-bottom:after {
    /* symbol for "opening" panels */
    font-family: 'Glyphicons Halflings';  /* essential for enabling glyphicon */
    content: "\e113";    /* adjust as needed, taken from bootstrap.css */
    float: right;        /* adjust as needed */
    color: grey;         /* adjust as needed */
}
.panel-footer .accordion-toggle-bottom.collapsed:after {
    /* symbol for "collapsed" panels */
    content: "\e114";     /* adjust as needed, taken from bootstrap.css */
}

// STRY0116823 
#myOverview {
  position: absolute;
  width: 200px;
  height: 100px;
  top: 115px;
  left: 15px;
  background-color: #f2f2f2;
  z-index: 300; // make sure its in front
  border: solid 1px #7986cb;
}

.page-map {
  //margin-top: .5em;
  //margin-bottom: .5em;
  //border: 1px solid #ddd;
  //width:100%;
  //height:120px;
  background-color: white;
}

.designer-link {
  margin-top: .5em;
  margin-bottom: .5em;
  padding-left: 8px;  
}

