sp_widget.script:
// Copyrights belong to Discover Technologies LLC. © 2021 Discover Technologies LLC
// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: KARINA TORRES
// RECURSIVE GRAPHICAL TASK TREE
//------------------------------------------------------------------------------------------------------------------------
//
// 2.7.0 | 2021-06-25 | mmcc | STRY0102408 "Task Tree Manager" tool tip displays "Unicode Decimal Codes" when entering 
//											some special characters in "instruction" or "Signature Instructions" field
//                                          Changes in Client controller
// 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode Decimal Codes when entering 
//											some special characters in "instruction" or "Signature Instructions" field
//                                          Changes in Client controller
// 2.7.0 | 2021-08-20 | mmcc | STRY0107808 - DIA-Scheduled Draft- Tree View Widget- Add Draft State
//											In HTML, Removed commented out code, Removed div id="legendStatus", 
//												Added span class="label label-Draft"
//											In CSS, Added selector for .label-Draft
//                                          Changes in HTML and CSS
// 2.7.0 | 2021-08-23 | mmcc | STRY0104983 - Stretch- Technical Debt - Update CSS to organize into proper hierarchy of CSS
//                                         Round 2. 
//                                         In CSS, Move State styling to Tasker State CSS Include
//                                         Changes made in CSS
// 2.7.0 | 2021-08-27 | mmcc | STRY0107400 - Draft Scheduled Tasks – UI – Publish from Subtasks
//                                         In HTML, removed unused <div id="infoBoxHolder">; added <div id="draftTaskPublishMessage">
//											to show/hide the info icon and Draft task publish message
//                                         In CSS, Removed unused #infoBoxHolder selector; added #draftTaskPublishMessage to keep
//											 a height of 30px so there is no bounce when show/hide of message;
//                                         In Server script, added data.draftTaskPublishMessage to get message for Draft task publish message;
//											added data.isTopTaskOrNotDraft = true at the top else the Draft task publish message shows before tree loads; 
//										   In Client controller, updated nodeSelectionChanged() to show a Draft publish message when 
//											Task State is Draft but not show that message for the top node.
//                                         Changes made in HTML, CSS, Server script and Client controller
// 2.7.0 | 2021-09-03 | raj   | STRY0109208 - Add Create Icon
//											Changes in Server Script and Client Script
// 2.7.0 | 2021-11-02 | mmcc | DFCT0010588 - When creating a Subtask on the Task form, record watcher shows 2 subtasks created
//											In Client controller, recordWatch() case insert, added if() .model.findNodeDataForKey() that 
//											returns null if a node with that key cannot be found; which should only add the node once
//                                          Changes in Client controller
// 2.7.0 | 2021-11-16 | raj  | DFCT0010652	"Open Task Tree View" button on Task Form opens a modal but user needs to click again to expand Task Tree View
//											Changes in Server Script, Client Controller and HTML
// 2.7.0 | 2021-11-17 | raj  | DFCT0010654 - Spelling Mistake: The "Add a Subtask" plus '+' icon in the Task/Template Information section displays the incorrect tooltip
//                                         Changes made in Server Script
// 2.7.1 | 2021-12-05 | raj  | DFCT0010684	Task Tree Nodes- "Add Subtask Icon" does not pick up Record Watcher
//																					Changes made in Server Script and Client Script
// 2.7.101 | 2021-12-23 | raj  | DFCT0010674 - The "Task Tree View" modal from the task form generates errors and does NOT always display the tree nodes
//																					Changes made in Server Script and Client Script

// 2.7.3   | 2022-05-09 | raj  | DFCT0010906 - TBD: Null displays on the Task order state 
//											Changes made inClient Script



// 2.8 | 2021-12-23 | raj  | STRY0119599 - Task Form Page Layout- Layout: Tree 
//																					Changes made in Server Script and Client Script and HTML
//
// 2.8   - 2022-04-20 - raj -  STRY0119818 - Task Tree Widget- New Buttons modify Zoom/Structure preferences
//                                           NOTE: also reorganized Template and OU to put all of the repeated functions in the same block of code
//                                         - Changes in Client Controller
// 2.8   - 2022-06-08 - raj -  STRY0122767 - Draft Task- Update "Publish Task(s)" buttons locations; Update Messaging for "Where to Publish Task(s)"
//                                         - Changes in HTML
// 2.8 | 2022-06-22 | mmcc | STRY0120303 - Task Tree Widget- Add Header and Footer area
//                                      In HTML, updated panel-group to flex row and grow, updated panel panel-default to flex column and grow,
//                                        updated show hide_accordion or isNotCollapsed to flex column and grow, updated ngClass !hide accordion 
//                                        to flex column and grow, updated show data.id to flex column and grow, deleted commented out panel-body,
//                                        deleted div for page_map_wrapper and it's parent div.
//                                      In CSS, deleted some selectors. 
//                                      In Client controller, function resizeDiagram() had all commented out code deleted and
//                                        not calculating height since using Flexbox
//                                      Changes made in HTML, CSS and Client controller
// 2.8   - 2022-07-04 - raj -  STRY0124682 - Task Tree Widget- "Information Icon" matches the Task Form "Information Icon" - NOTE also updated Template Tree
//                                         - Changes in Client Controller
// 2.8   - 2022-07-11 - raj -  STRY0121780 - Stretch- Task Tree Widget UX- Update user's "tree-view" preferences
//                                         - Changes in ServerScript only
//  2.8   - 2022-08-03 - raj -  DFCT0011129 - "Task Tree View"  on the "Three column" view is NOT updating  the new subtask on the load
//                                         - Changes in Client Controller
//  2.8   - 2022-08-16 - raj -  DFCT0011179 - Record watcher:  Task Tree View widget is NOT updating word "to" to "by"  when the state flow changes 
//                                         - Changes in Client Controller
//  2.8   - 2022-08-16 - raj -  DFCT0011096 - Task Tree view- "Navigate to Top Task" button does NOT send users to Top Task 
//                                           Changes in Server Script, Client Controller and HTML.  replaced data.id with data.topParentTask_id everywhere
//  2.8   - 2022-08-16 - raj - DFCT0011078 - Long Task name should NOT impact the  "Task Name", "state" and  "user" name in the Task Tree View
//  2.8   - 2022-08-16 - raj - STRY0127737 - Task Tree/Template Task Tree- New Design for Overflow Text 
//																						Changes in Client Controller
// 2.8 | 2022-08-19 | mmcc | DFCT0011084 - Page Tree Bi-Fold needs to match the standard layout for flexing header-body-footer
//                                      In HTML, add position absolute to id="main_body" when bifold; add standard height CSS selector to panel-heading
//                                      In Server script, add bifold
//                                      Changes made in HTML and Server script.
// 2.8   - 2022-08-20 - raj - DFCT0011140 - Record watcher: "Warning Icon" &  "Duration icon"  should NOT trigger the visual warning indicator on load. (Taker Type "Approval)
//																			Changes made in Client Controller
// 2.8   - 2022-08-23 - raj - DFCT0011227 -  Long Task name should NOT impact the  "Task Name", "state" and  "user" name in any "State"
//																			Changes made in Client Controller
// 2.8   - 2022-08-29 - raj - STRY0128732 Task Tree- Improved Messaging for Decision Made on Approval and Concurrence Tasker Types
//																			Changes made in Client Controller
// 2.8 | 2022-08-30 | mmcc | DFCT0011242 - Add Subtask modal does NOT display the UI action buttons. Create Task, Draft Tasks  (Modal are NOT scrolling)
//                                      In HTML, dropped ngclass if bifold to add CSS for position absolute, now always there
//                                      Changes made in HTML.
// 2.8 | 2022-09-01 | mmcc | DFCT0011272 - "Task Tree View"  does NOT open on the  Three Column view (It is hidden behind the Task List View and Summary Card)
//                                      In HTML, use ngclass to add position absolute when data.hide_accordion = true, above defect broke it
//                                      Changes made in HTML.
// 2.8 | 2022-09-02 | raj  |  DFCT0011271 - New Task form loads Parent Tasker Type, but shows the last selection of the user
//                                      Changes in Server Script
// 2.8 | 2022-09-02 | mmcc | DFCT0011213 - In Tree Bi-Fold, in Subtask tab, Task Progress Bar PUSHES content off on certain monitor sizes
//                                      In HTML, update panel heading to use ngclass when bifold to add min height standard
//                                      Changes made in HTML.
// 2.8 | 2022-09-21 | mmcc | STRY0129140 - Task/Template Tree- Add "TaskFlow (tm)"
//                                      In HTML, replaced style attribute with CSS selector .text-right; 
//                                      added 2 div's relative and absolute to position TaskFlowTM_Logo.svg
//                                      In Client controller, added missing semicolon to $scope.toggleCollpased and formatted file
//                                      Changes made in HTML and Client controller.
//
//------------------------------------------------------------------------------------------------------------------------

(function() {

    main();

    function main() {
        var taskWidgetIconsAndMessage = new TaskerWidgetIconsAndMessages('discovertasker-recursivetasktreegraph');
        data.settings = taskWidgetIconsAndMessage.loadDefaultsAndSettings($sp);
        data.messages = taskWidgetIconsAndMessage.loadMessages();
        data.icons = taskWidgetIconsAndMessage.loadIcons();

        // DFCT0010684
        data.currentUser = gs.getUserID();
        // DFCT0010652
        data.hide_accordion = (input || {}).hide_accordion || (options || {}).hide_accordion || false;
        // 2.7.0 | 2021-08-27 | mmcc | STRY0107400 - Draft Scheduled Tasks – UI – Publish from Subtasks
        data.isTopTaskOrNotDraft = true;
        data.loadData = false;
        // DFCT0010674
        data.selectedId = (input || {}).sys_id || $sp.getParameter('sys_id');
        data.table = (input || {}).table || $sp.getParameter('table');

        // 2.8 | 2022-08-19 | mmcc | DFCT0011084 - Page Tree Bi-Fold needs to match the standard layout for flexing header-body-footer; add bifold
        data.bifold = (input || {}).bifold || (options || {}).bifold || false;

        // 2.8 | 2022-08-19 | mmcc | DFCT0011084 - Page Tree Bi-Fold needs to match the standard layout for flexing header-body-footer; add bifold
        // DFCT0010674 - STRY0119599
        convertToBool(['bifold', 'hide_accordion']);

        data.dynamic_tree = $sp.getParameter("dynamic_tree"); // KT - TLV - STRY0057360 - Macro Widget
        if ((data.table != "x_153465_discovert_route_task_instance") || (!data.selectedId)) {
            data.topParentTask_id = null;
            return;
        }
        if (input) {
            data.loadData = input.loadData;
        }

        // DFCT0010674 - STRY0119599
        if (data.hide_accordion) {
            data.loadData = true;
        }

        if (data.loadData) {
            _loadTaskTree();
            // STRY0121780 - moved here load toolbar after loading task tree
            _loadToolBars();

        }
    }

    function _loadToolBars() {
        // TREE HEADER TOOLBAR
        // STRY0117600 - move toolbar into separate widget to use same functionality across all
        // STRY0120908 - added show separator
        var header_widget_parameters = {
            baseWidget: 'discovertasker-recursivetasktreegraph',
            // STRY0121780
            topId: data.topParentTask_id,
            showSeparator: !data.hide_accordion,
            iconGroup: 'header'
        };
        data.widgetTreeHeaderToolbars = [];
        data.widgetTreeHeaderToolbars.push($sp.getWidget('tasker-tree-toolbar-icons', header_widget_parameters));

        // TREE FOOTER TOOLBAR
        // STRY0117600 - move toolbar into separate widget to use same functionality across all
        var footer_widget_parameters = {
            baseWidget: 'discovertasker-recursivetasktreegraph',
            // STRY0121780
            topId: data.topParentTask_id,
            iconGroup: 'footer'
        };
        data.widgetTreeFooterToolbars = [];
        data.widgetTreeFooterToolbars.push($sp.getWidget('tasker-tree-toolbar-icons', footer_widget_parameters));
    }

    function _loadTaskTree() {

        var grTask = new GlideRecordSecure('x_153465_discovert_route_task_instance');
        if (!grTask.get(data.selectedId)) {
            data.topParentTask_id = null;
            return;
        }
        var id = grTask.getValue("u_top_task");

        var grTopTask = new GlideRecordSecure('x_153465_discovert_route_task_instance');
        if (!grTopTask.get(id)) {
            data.topParentTask_id = null;
            return;
        }
        // DFCT0011096 - replaced data.id with data.topParentTask_id everywhere
        data.topParentTask_id = grTopTask.getValue('sys_id');

        data.task_tree = grTopTask.getValue('u_task_tree');

        // STRY0091251 - NOTE: this uses the same data building functions as the 'Tasker List Task Tree' widget id: discovertasker-recursivetasktreelist
        if (data.loadData) {
            // DFCT0010674
            var map = data.map = [];
            var taskWidgetData = new TaskWidgetData();
            data.fieldsInModel = taskWidgetData.loadTaskTreeFieldsInModelAndFieldLabels(grTopTask);
            taskWidgetData.buildTaskMap('discovertasker-recursivetasktreegraph', map, grTopTask, data.fieldsInModel);
        }
    }

    function convertToBool(names) {
        names.forEach(function(name) {
            data[name] = data[name] == true || data[name] == 'true';
        });
    }

})();
